import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import logo from '../assets/blouge.svg';
import { login } from '../services/api';
import '../styles/Login.css';

export default function Login() {
    const navigate = useNavigate();
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState('');

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        setError('');

        try {
            const user = await login(email, password);
            if (user) {
                navigate('/groups');
            } else {
                setError('Email ou mot de passe incorrect.');
            }
        } catch (err) {
            setError('Une erreur est survenue.');
        } finally {
            setLoading(false);
        }
    };

    const handleForgotPassword = () => {
        alert("Fonctionnalité à venir : récupération du mot de passe !");
        // Tu pourras plus tard rediriger vers /forgot-password par exemple
    };

    return (
        <div className="login-container">
            <div className="login-card">
                <img src={logo} alt="Logo Blouge" className="login-logo" />

                <h1 className="login-title">Connexion</h1>

                <form onSubmit={handleSubmit}>
                    <div>
                        <label className="login-label">Email</label>
                        <input
                            type="email"
                            value={email}
                            onChange={(e) => setEmail(e.target.value)}
                            className="login-input"
                            required
                        />
                    </div>

                    <div>
                        <label className="login-label">Mot de passe</label>
                        <input
                            type="password"
                            value={password}
                            onChange={(e) => setPassword(e.target.value)}
                            className="login-input"
                            required
                        />
                    </div>

                    {error && <p className="login-error">{error}</p>}

                    <button type="submit" className="login-button" disabled={loading}>
                        {loading ? 'Connexion en cours...' : 'Se connecter'}
                    </button>

                    <button
                        type="button"
                        onClick={handleForgotPassword}
                        className="login-link"
                    >
                        Mot de passe oublié ?
                    </button>
                </form>
            </div>
        </div>
    );
}
